import { useEffect, useState } from "react";
import * as signalR from "@microsoft/signalr";
import { getLoggedUserToken } from "@/feature/auth/services/auth-service"; 
import { MessageType, SendMessage } from "@/types/messages";

export const useChat = (groupId?: number) => {
    const [connection, setConnection] = useState<signalR.HubConnection | null>(null);
    const [messages, setMessages] = useState<MessageType[]>([]); // Troque 'any' pelo seu MessageDto

    useEffect(() => {
        const connect = async () => {
            const token = await getLoggedUserToken();

            const newConnection = new signalR.HubConnectionBuilder()
            .withUrl(`http://localhost:5000/hubs/chat`, {
                accessTokenFactory: () => token || "" 
            })
            .withAutomaticReconnect()
            .build();

            newConnection.on("ReceiveMessage", (message) => {
                setMessages((prev) => [...prev, message]);
            });

            try {
                await newConnection.start();
                console.log("SignalR Connected!");

                if (groupId) {
                    await newConnection.invoke("JoinGroup", groupId);
                }

                setConnection(newConnection);
            } catch (error) {
                console.error("Erro ao conectar no SignalR:", error);
            }
        };

        connect();

        return () => {
            if (connection) {
                if (groupId) {
                    connection.invoke("LeaveGroup", groupId).catch(console.error);
                }
                connection.stop();
            }
        };
    }, [groupId]); 

    const sendMessage = async (sendMessageDto: SendMessage) => {
        if (connection && connection.state === signalR.HubConnectionState.Connected) {
            try {
                await connection.invoke("SendMessage", sendMessageDto);
            } catch (error) {
                console.error("Erro ao enviar mensagem:", error);
            }
        }
    };

    return { messages, sendMessage, connection };
};